#include <stdio.h>
#include "platform.h"
#include "xil_printf.h"
#include "xparameters.h"
#include <xil_io.h>
#include <sleep.h>

#define PhyRead(addr) Xil_In32(addr)
#define PhyWrite(addr, value) Xil_Out32(addr, value)
#define AXILITE_BASEADDR XPAR_AXI_ADAPTER_0_BASEADDR + 0x8000000

int main()
{
    init_platform();

    print("Hello World\n\r");
    for(int i=0;i<3;i++)
    {
        sleep(1);
        printf("i is %d\n\r",i);
    }
    int reg0in  = 320;
    int reg0out = 0;

    //可以通过debug模式查看memory，对比没有disable的情况
    Xil_DCacheDisable();
    for(int i = 0; i < 32; i+=4)
    {
    	reg0out = PhyRead(AXILITE_BASEADDR + i);
    	PhyWrite(AXILITE_BASEADDR + i, reg0out + 4);
    	printf("reg0out %x is %d\r\n", AXILITE_BASEADDR + i, reg0out + 4);
    }

    cleanup_platform();
    return 0;
}
