下面是串口接收代码。实际运行时，发现i有时候会从10跳变为2或8，但程序中却没有这样的语句，让人百思不得其解。


```verilog
module UARTReceiver #(
    parameter SYSCLK = 50000000
    )(
    input clock, // 系统时钟
    input nrst, // 模块复位
    input rx, // 串口接收引脚
    input [23:0] baud_rate, // 波特率
    output reg received, // 是否收到了数据
    output reg [7:0] data // 收到的数据内容 (received信号为上升沿或者高电平时才可以读取)
    );

wire _rx = rx;

integer counter; // 波特率计数器
reg [3:0] bit_i; // 当前正在接收第几位数据 (0为起始位, 1-8为数据位, 9为停止位, 10为空闲)
wire bit_sample = (counter == SYSCLK / baud_rate / 2 - 1); // 采样信号
wire bit_end = (counter == SYSCLK / baud_rate - 1); // 位结束信号

// 接收数据
always @(posedge clock, negedge nrst) begin
    if (!nrst) begin
        // 模块复位
        bit_i <= 10;
        counter <= 0;
        received <= 0;
    end
    else begin
        if (bit_i <= 9) begin
            if (bit_end) begin
                // 当前位结束, 准备接收下一位
                bit_i <= bit_i + 1'b1;
                counter <= 0;
            end
            else begin
                if (bit_sample) begin
                    // 当前位数据采样
                    if (bit_i == 0 && _rx)
                        bit_i <= 10; // 起始位错误, 停止接收
                    else if (bit_i >= 1 && bit_i <= 8)
                        data[bit_i - 1] <= _rx; // 收到数据位
                    else if (bit_i == 9) begin
                        // 收到停止位
                        bit_i <= 10; // 接收完毕
                        if (_rx)
                            received <= 1;
                    end
                end
                counter <= counter + 1;
            end
        end
        else if (!_rx) begin
            // 检测到起始位, 开始接收
            bit_i <= 0;
            counter <= 1;
            received <= 0;
        end
        else begin
            // 空闲
            if (bit_end) begin
                counter <= 0;
                received <= 0;
            end
            else if (counter != 0)
                counter <= counter + 1;
        end
    end
end
endmodule
```

