```c++
#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <unordered_map>
#include <pcapplusplus/IPv4Layer.h>
#include <pcapplusplus/Packet.h>
#include <pcapplusplus/PcapFileDevice.h>
#include <pcapplusplus/TcpLayer.h>
#include <filesystem>

using namespace std;
using namespace pcpp;
namespace fs = std::filesystem;

struct SessionKey {
    IPv4Address srcIp;
    IPv4Address dstIp;
    uint16_t srcPort;
    uint16_t dstPort;
    ProtocolType protocol;

    bool operator==(const SessionKey& other) const {
        return srcIp == other.srcIp && dstIp == other.dstIp && srcPort == other.srcPort && dstPort == other.dstPort && protocol == other.protocol;
    }
};

namespace std {
    template <>
    class hash<SessionKey> {
    public:
        size_t operator()(const SessionKey& key) const {
            return hash<string>()(key.srcIp.toString() + key.dstIp.toString() + to_string(key.srcPort) + to_string(key.dstPort) + to_string(static_cast<int>(key.protocol)));
        }
    };
}

int main(int argc, char* argv[]) {
    if (argc < 3) {
        cerr << "Usage: " << argv[0] << " <input pcap file> <output directory>" << endl;
        return 1;
    }

    string inputPcapFile = argv[1];
    string outputDir = argv[2];

    // 打开输入 pcap 文件
    IFileReaderDevice* reader = IFileReaderDevice::getReader(inputPcapFile);
    if (!reader) {
        cerr << "Cannot determine reader for file type" << endl;
        return 1;
    }
    if (!reader->open()) {
        cerr << "Cannot open " << inputPcapFile << " for reading" << endl;
        return 1;
    }

    // 创建输出目录
    try {
        fs::create_directories(outputDir);
    } catch (const fs::filesystem_error& e) {
        cerr << "Cannot create output directory: " << outputDir << endl;
        cerr << "Error: " << e.what() << endl;
        return 1;
    }

    unordered_map<SessionKey, vector<RawPacket>> sessions;

    RawPacket rawPacket;
    while (reader->getNextPacket(rawPacket)) {
        Packet parsedPacket(&rawPacket);
        if (parsedPacket.isPacketOfType(pcpp::IPv4) && parsedPacket.isPacketOfType(pcpp::TCP)) {
            IPv4Layer* ipLayer = parsedPacket.getLayerOfType<IPv4Layer>();
            TcpLayer* tcpLayer = parsedPacket.getLayerOfType<TcpLayer>();

            SessionKey key = {
                ipLayer->getSrcIPv4Address(),
                ipLayer->getDstIPv4Address(),
                tcpLayer->getSrcPort(),
                tcpLayer->getDstPort(),
                pcpp::IPv4  // 假设协议类型为 IPv4
            };

            sessions[key].push_back(rawPacket);
        }
    }

    reader->close();

    // 保存每个会话到单独的 pcap 文件
    for (const auto& session : sessions) {
        string sessionFileName = outputDir + "/" + session.first.srcIp.toString() + "_" + session.first.dstIp.toString() + "_" + to_string(session.first.srcPort) + "_" + to_string(session.first.dstPort) + ".pcap";
        PcapFileWriterDevice writer(sessionFileName, LINKTYPE_ETHERNET);
        if (!writer.open()) {
            cerr << "Cannot open " << sessionFileName << " for writing" << endl;
            continue;
        }

        for (const auto& packet : session.second) {
            writer.writePacket(packet);
        }

        writer.close();
    }

    return 0;
}
